-- OMO-3197: 성원 쇼핑백 4종 연동 — 라이브 재크롤 옵션 시드
-- 생성: scripts/omo3197-gen-migration.mjs ← scripts/omo3197-bag-options.json (2026-06-15)
-- 성원 상단 4버튼 = 4 category_code. DB 기존 옵션(100/200/500 등 임의값)을
-- 실측 성원 옵션(paper_code/paper_size/paper_qty)으로 교체한다.
--
-- ⚠️ 수량별 PRICING 은 미포함: 성원 쇼핑백 가격행렬은 index(unit_key) 기반이라
--    json_data 로 수량↔단가 매핑이 불가(calcuEstimate 인터랙티브 경로 필요).
--    → 신규 2종은 is_active=FALSE(드래프트), 가격 엔진은 후속 이슈에서 연동.
BEGIN;

-- ========== CPK4000 → paper-shopping-bags (종이끈 쇼핑백) ==========
DELETE FROM print_product_options WHERE product_id = (SELECT id FROM print_products WHERE slug='paper-shopping-bags')
  AND option_type IN ('paper','size','quantity','paper_code','paper_size','paper_qty','print_color_type');

-- ========== CPK2000 → gift-bags (리본&브레이드 쇼핑백) ==========
DELETE FROM print_product_options WHERE product_id = (SELECT id FROM print_products WHERE slug='gift-bags')
  AND option_type IN ('paper','size','quantity','paper_code','paper_size','paper_qty','print_color_type');

-- ========== CPK3000 → handleless-bags (끈없는 쇼핑백) ==========
  slug, name_ko, name_en, category, base_price_krw, margin_multiplier,
  sort_order, is_active, min_order_quantity, production_days_min, production_days_max, unit_weight_g
) VALUES (
  'handleless-bags', '끈없는 쇼핑백', 'Handleless Bags', 'paper_bags', 110000, 4,
  50, FALSE, 1, 2, 4, 70
) ON CONFLICT (slug) DO NOTHING;
DELETE FROM print_product_options WHERE product_id = (SELECT id FROM print_products WHERE slug='handleless-bags')
  AND option_type IN ('paper','size','quantity','paper_code','paper_size','paper_qty','print_color_type');

-- ========== CPK5000 → small-batch-bags (소량 쇼핑백) ==========
  slug, name_ko, name_en, category, base_price_krw, margin_multiplier,
  sort_order, is_active, min_order_quantity, production_days_min, production_days_max, unit_weight_g
) VALUES (
  'small-batch-bags', '소량 쇼핑백', 'Small-Batch Bags', 'paper_bags', 64000, 4,
  50, FALSE, 1, 2, 4, 60
) ON CONFLICT (slug) DO NOTHING;
DELETE FROM print_product_options WHERE product_id = (SELECT id FROM print_products WHERE slug='small-batch-bags')
  AND option_type IN ('paper','size','quantity','paper_code','paper_size','paper_qty','print_color_type');

COMMIT;
